import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { 
  Home, 
  PlusCircle, 
  List, 
  LayoutDashboard, 
  CreditCard, 
  Wallet 
} from 'lucide-react';

const Sidebar = () => {
  const location = useLocation();

  // Estilo base para os itens do menu
  const linkStyle = (path) => ({
    display: 'flex',
    alignItems: 'center',
    gap: '15px',
    padding: '12px 20px',
    textDecoration: 'none',
    color: location.pathname === path ? '#4361ee' : '#576574',
    fontWeight: location.pathname === path ? '700' : '500',
    borderRadius: '12px',
    transition: 'all 0.2s ease',
    backgroundColor: location.pathname === path ? '#f0f3ff' : 'transparent',
    marginBottom: '8px'
  });

  return (
    <div style={sidebarContainerStyle}>
      {/* LOGO */}
      <div style={logoStyle}>
        <Wallet size={32} color="#1e272e" />
        <span style={{ fontSize: '1.5rem', fontWeight: 800, color: '#1e272e' }}>Finanças</span>
      </div>

      <nav style={{ marginTop: '40px' }}>
        <Link to="/" style={linkStyle('/')}>
          <Home size={22} /> Início
        </Link>

        <Link to="/lancamento" style={linkStyle('/lancamento')}>
          <PlusCircle size={22} /> Novo Lançamento
        </Link>

        <Link to="/despesas" style={linkStyle('/despesas')}>
          <List size={22} /> Minhas Despesas
        </Link>

        {/* NOVO ACESSO: MEUS CARTÕES */}
        <Link to="/cartoes" style={linkStyle('/cartoes')}>
          <CreditCard size={22} /> Meus Cartões
        </Link>

        <Link to="/dashboard" style={linkStyle('/dashboard')}>
          <LayoutDashboard size={22} /> Dashboard
        </Link>
      </nav>
    </div>
  );
};

/* ESTILOS INTERNOS */
const sidebarContainerStyle = {
  width: '280px',
  height: '100vh',
  backgroundColor: 'white',
  borderRight: '1px solid #e1e8ed',
  padding: '30px 20px',
  position: 'fixed',
  left: 0,
  top: 0
};

const logoStyle = {
  display: 'flex',
  alignItems: 'center',
  gap: '12px',
  paddingLeft: '10px'
};

export default Sidebar;
